// WRONG: cartesian explosion với 2+ collections
var orders = await db.Orders
    .Include(o => o.Items)    // 10 items/order
    .Include(o => o.Tags)     // 5 tags/order
    .Include(o => o.Comments) // 3 comments/order
    .ToListAsync();           // rows = 10×5×3 = 150 per order!

// RIGHT: Split queries
var orders = await db.Orders
    .Include(o => o.Items)
    .Include(o => o.Tags)
    .Include(o => o.Comments)
    .AsSplitQuery()           // 4 SELECT riêng biệt
    .ToListAsync();

// Global config
protected override void OnConfiguring(DbContextOptionsBuilder opt) =>
    opt.UseNpgsql(conn, o => o.UseQuerySplittingBehavior(
        QuerySplittingBehavior.SplitQuery));

// Override per-query
var result = await db.Orders.Include(o => o.Items)
    .AsSingleQuery()          // override global split config
    .ToListAsync();
